    14→package parser
    15→
    16→import (
    17→	"context"
    18→	"fmt"
    19→	"time"
    20→
    21→	"github.com/prometheus/prometheus/model/labels"
    22→	"github.com/prometheus/prometheus/promql/parser/posrange"
    23→	"github.com/prometheus/prometheus/storage"
    24→)
    25→
    26→// Node is a generic interface for all nodes in an AST.
    27→//
    28→// Whenever numerous nodes are listed such as in a switch-case statement
    29→// or a chain of function definitions (e.g. String(), PromQLExpr(), etc.) convention is
    30→// to list them as follows:
    31→//
    32→//   - Statements
    33→//   - statement types (alphabetical)
    34→//   - ...
    35→//   - Expressions
    36→//   - expression types (alphabetical)
    37→//   - ...
    38→type Node interface {
    39→	// String representation of the node that returns the given node when parsed
    40→	// as part of a valid query.
    41→	String() string
    42→
    43→	// Pretty returns the prettified representation of the node.
    44→	// It uses the level information to determine at which level/depth the current
    45→	// node is in the AST and uses this to apply indentation.
    46→	Pretty(level int) string
    47→
    48→	// PositionRange returns the position of the AST Node in the query string.
    49→	PositionRange() posrange.PositionRange
    50→}
    51→
    52→// Statement is a generic interface for all statements.
    53→type Statement interface {
    54→	Node
    55→
    56→	// PromQLStmt ensures that no other type accidentally implements the interface
    57→	PromQLStmt()
    58→}
    59→
    60→// EvalStmt holds an expression and information on the range it should
    61→// be evaluated on.
    62→type EvalStmt struct {
    63→	Expr Expr // Expression to be evaluated.
    64→
    65→	// The time boundaries for the evaluation. If Start equals End an instant
    66→	// is evaluated.
    67→	Start, End time.Time
    68→	// Time between two evaluated instants for the range [Start:End].
    69→	Interval time.Duration
    70→	// Lookback delta to use for this evaluation.
    71→	LookbackDelta time.Duration
    72→}
    73→
    74→func (*EvalStmt) PromQLStmt() {}
    75→
    76→// Expr is a generic interface for all expression types.
    77→type Expr interface {
    78→	Node
    79→
    80→	// Type returns the type the expression evaluates to. It does not perform
    81→	// in-depth checks as this is done at parsing-time.
    82→	Type() ValueType
    83→	// PromQLExpr ensures that no other types accidentally implement the interface.
    84→	PromQLExpr()
    85→}
    86→
    87→// Expressions is a list of expression nodes that implements Node.
    88→type Expressions []Expr
    89→
    90→// AggregateExpr represents an aggregation operation on a Vector.
    91→type AggregateExpr struct {
    92→	Op       ItemType // The used aggregation operation.
    93→	Expr     Expr     // The Vector expression over which is aggregated.
    94→	Param    Expr     // Parameter used by some aggregators.
    95→	Grouping []string // The labels by which to group the Vector.
    96→	Without  bool     // Whether to drop the given labels rather than keep them.
    97→	PosRange posrange.PositionRange
    98→}
    99→
   100→// BinaryExpr represents a binary expression between two child expressions.
   101→type BinaryExpr struct {
   102→	Op       ItemType // The operation of the expression.
   103→	LHS, RHS Expr     // The operands on the respective sides of the operator.
   104→
   105→	// The matching behavior for the operation if both operands are Vectors.
   106→	// If they are not this field is nil.
   107→	VectorMatching *VectorMatching
   108→
   109→	// If a comparison operator, return 0/1 rather than filtering.
   110→	ReturnBool bool
   111→}
   112→
   113→// DurationExpr represents a binary expression between two duration expressions.
   114→type DurationExpr struct {
   115→	Op       ItemType // The operation of the expression.
   116→	LHS, RHS Expr     // The operands on the respective sides of the operator.
   117→	Wrapped  bool     // Set when the duration is wrapped in parentheses.
   118→
   119→	StartPos posrange.Pos // For unary operations, step(), and range(), the start position of the operator.
   120→	EndPos   posrange.Pos // For step() and range(), the end position of the operator.
   121→}
   122→
   123→// Call represents a function call.
   124→type Call struct {
   125→	Func *Function   // The function that was called.
   126→	Args Expressions // Arguments used in the call.
   127→
   128→	PosRange posrange.PositionRange
   129→}
   130→
   131→// MatrixSelector represents a Matrix selection.
   132→type MatrixSelector struct {
   133→	// It is safe to assume that this is an VectorSelector
   134→	// if the parser hasn't returned an error.
   135→	VectorSelector Expr
   136→	Range          time.Duration
   137→	RangeExpr      *DurationExpr
   138→	EndPos         posrange.Pos
   139→}
   140→
   141→// SubqueryExpr represents a subquery.
   142→type SubqueryExpr struct {
   143→	Expr      Expr
   144→	Range     time.Duration
   145→	RangeExpr *DurationExpr
   146→	// OriginalOffset is the actual offset that was set in the query.
   147→	OriginalOffset time.Duration
   148→	// OriginalOffsetExpr is the actual offset expression that was set in the query.
   149→	OriginalOffsetExpr *DurationExpr
   150→	// Offset is the offset used during the query execution
   151→	// which is calculated using the original offset, offset expression, at modifier time,
   152→	// eval time, and subquery offsets in the AST tree.
   153→	Offset     time.Duration
   154→	Timestamp  *int64
   155→	StartOrEnd ItemType // Set when @ is used with start() or end()
   156→	Step       time.Duration
   157→	StepExpr   *DurationExpr
   158→
   159→	EndPos posrange.Pos
   160→}
   161→
   162→// NumberLiteral represents a number.
   163→type NumberLiteral struct {
   164→	Val float64
   165→
   166→	Duration bool // Used to format the number as a duration.
   167→	PosRange posrange.PositionRange
   168→}
   169→
   170→// ParenExpr wraps an expression so it cannot be disassembled as a consequence
   171→// of operator precedence.
   172→type ParenExpr struct {
   173→	Expr     Expr
   174→	PosRange posrange.PositionRange
   175→}
   176→
   177→// StringLiteral represents a string.
   178→type StringLiteral struct {
   179→	Val      string
   180→	PosRange posrange.PositionRange
   181→}
   182→
   183→// UnaryExpr represents a unary operation on another expression.
   184→// Currently unary operations are only supported for Scalars.
   185→type UnaryExpr struct {
   186→	Op   ItemType
   187→	Expr Expr
   188→
   189→	StartPos posrange.Pos
   190→}
   191→
   192→// StepInvariantExpr represents a query which evaluates to the same result
   193→// irrespective of the evaluation time given the raw samples from TSDB remain unchanged.
   194→// Currently this is only used for engine optimisations and the parser does not produce this.
   195→type StepInvariantExpr struct {
   196→	Expr Expr
   197→}
   198→
   199→func (e *StepInvariantExpr) String() string { return e.Expr.String() }
   200→
   201→func (e *StepInvariantExpr) PositionRange() posrange.PositionRange {
   202→	return e.Expr.PositionRange()
   203→}
   204→
   205→// VectorSelector represents a Vector selection.
   206→type VectorSelector struct {
   207→	Name string
   208→	// OriginalOffset is the actual offset calculated from OriginalOffsetExpr.
   209→	OriginalOffset time.Duration
   210→	// OriginalOffsetExpr is the actual offset that was set in the query.
   211→	OriginalOffsetExpr *DurationExpr
   212→	// Offset is the offset used during the query execution
   213→	// which is calculated using the original offset, at modifier time,
   214→	// eval time, and subquery offsets in the AST tree.
   215→	Offset               time.Duration
   216→	Timestamp            *int64
   217→	SkipHistogramBuckets bool     // Set when decoding native histogram buckets is not needed for query evaluation.
   218→	StartOrEnd           ItemType // Set when @ is used with start() or end()
   219→	LabelMatchers        []*labels.Matcher
   220→
   221→	// The unexpanded seriesSet populated at query preparation time.
   222→	UnexpandedSeriesSet storage.SeriesSet
   223→	Series              []storage.Series
   224→
   225→	// BypassEmptyMatcherCheck is true when the VectorSelector isn't required to have at least one matcher matching the empty string.
   226→	// This is the case when VectorSelector is used to represent the info function's second argument.
   227→	BypassEmptyMatcherCheck bool
   228→
   229→	// Anchored is true when the VectorSelector is anchored.
   230→	Anchored bool
   231→	// Smoothed is true when the VectorSelector is smoothed.
   232→	Smoothed bool
   233→
   234→	PosRange posrange.PositionRange
   235→}
   236→
   237→// TestStmt is an internal helper statement that allows execution
   238→// of an arbitrary function during handling. It is used to test the Engine.
   239→type TestStmt func(context.Context) error
   240→
   241→func (TestStmt) String() string      { return "test statement" }
   242→func (TestStmt) PromQLStmt()         {}
   243→func (t TestStmt) Pretty(int) string { return t.String() }
   244→
   245→func (TestStmt) PositionRange() posrange.PositionRange {
   246→	return posrange.PositionRange{
   247→		Start: -1,
   248→		End:   -1,
   249→	}
   250→}
   251→func (*AggregateExpr) Type() ValueType  { return ValueTypeVector }
   252→func (e *Call) Type() ValueType         { return e.Func.ReturnType }
   253→func (*MatrixSelector) Type() ValueType { return ValueTypeMatrix }
   254→func (*SubqueryExpr) Type() ValueType   { return ValueTypeMatrix }
   255→func (*NumberLiteral) Type() ValueType  { return ValueTypeScalar }
   256→func (e *ParenExpr) Type() ValueType    { return e.Expr.Type() }
   257→func (*StringLiteral) Type() ValueType  { return ValueTypeString }
   258→func (e *UnaryExpr) Type() ValueType    { return e.Expr.Type() }
   259→func (*VectorSelector) Type() ValueType { return ValueTypeVector }
   260→func (e *BinaryExpr) Type() ValueType {
   261→	if e.LHS.Type() == ValueTypeScalar && e.RHS.Type() == ValueTypeScalar {
   262→		return ValueTypeScalar
   263→	}
   264→	return ValueTypeVector
   265→}
   266→func (e *StepInvariantExpr) Type() ValueType { return e.Expr.Type() }
   267→func (*DurationExpr) Type() ValueType        { return ValueTypeScalar }
   268→
   269→func (*AggregateExpr) PromQLExpr()     {}
   270→func (*BinaryExpr) PromQLExpr()        {}
   271→func (*Call) PromQLExpr()              {}
   272→func (*MatrixSelector) PromQLExpr()    {}
   273→func (*SubqueryExpr) PromQLExpr()      {}
   274→func (*NumberLiteral) PromQLExpr()     {}
   275→func (*ParenExpr) PromQLExpr()         {}
   276→func (*StringLiteral) PromQLExpr()     {}
   277→func (*UnaryExpr) PromQLExpr()         {}
   278→func (*VectorSelector) PromQLExpr()    {}
   279→func (*StepInvariantExpr) PromQLExpr() {}
   280→func (*DurationExpr) PromQLExpr()      {}
   281→
   282→// VectorMatchCardinality describes the cardinality relationship
   283→// of two Vectors in a binary operation.
   284→type VectorMatchCardinality int
   285→
   286→const (
   287→	CardOneToOne VectorMatchCardinality = iota
   288→	CardManyToOne
   289→	CardOneToMany
   290→	CardManyToMany
   291→)
   292→
   293→func (vmc VectorMatchCardinality) String() string {
   294→	switch vmc {
   295→	case CardOneToOne:
   296→		return "one-to-one"
   297→	case CardManyToOne:
   298→		return "many-to-one"
   299→	case CardOneToMany:
   300→		return "one-to-many"
   301→	case CardManyToMany:
   302→		return "many-to-many"
   303→	}
   304→	panic("promql.VectorMatchCardinality.String: unknown match cardinality")
   305→}
   306→
   307→// VectorMatching describes how elements from two Vectors in a binary
   308→// operation are supposed to be matched.
   309→type VectorMatching struct {
   310→	// The cardinality of the two Vectors.
   311→	Card VectorMatchCardinality
   312→	// MatchingLabels contains the labels which define equality of a pair of
   313→	// elements from the Vectors.
   314→	MatchingLabels []string
   315→	// On includes the given label names from matching,
   316→	// rather than excluding them.
   317→	On bool
   318→	// Include contains additional labels that should be included in
   319→	// the result from the side with the lower cardinality.
   320→	Include []string
   321→	// Fill-in values to use when a series from one side does not find a match on the other side.
   322→	FillValues VectorMatchFillValues
   323→}
   324→
   325→// VectorMatchFillValues contains the fill values to use for Vector matching
   326→// when one side does not find a match on the other side.
   327→// When a fill value is nil, no fill is applied for that side, and there
   328→// is no output for the match group if there is no match.
   329→type VectorMatchFillValues struct {
   330→	// RHS is the fill value to use for the right-hand side.
   331→	RHS *float64
   332→	// LHS is the fill value to use for the left-hand side.
   333→	LHS *float64
   334→}
   335→
   336→// Visitor allows visiting a Node and its child nodes. The Visit method is
   337→// invoked for each node with the path leading to the node provided additionally.
   338→// If the result visitor w is not nil and no error, Walk visits each of the children
   339→// of node with the visitor w, followed by a call of w.Visit(nil, nil).
   340→type Visitor interface {
   341→	Visit(node Node, path []Node) (w Visitor, err error)
   342→}
   343→
   344→// Walk traverses an AST in depth-first order: It starts by calling
   345→// v.Visit(node, path); node must not be nil. If the visitor w returned by
   346→// v.Visit(node, path) is not nil and the visitor returns no error, Walk is
   347→// invoked recursively with visitor w for each of the non-nil children of node,
   348→// followed by a call of w.Visit(nil), returning an error
   349→// As the tree is descended the path of previous nodes is provided.
   350→func Walk(v Visitor, node Node, path []Node) error {
   351→	var err error
   352→	if v, err = v.Visit(node, path); v == nil || err != nil {
   353→		return err
   354→	}
   355→	var pathToHere []Node // Initialized only when needed.
   356→
   357→	for e := range ChildrenIter(node) {
   358→		if pathToHere == nil {
   359→			pathToHere = append(path, node)
   360→		}
   361→		if err := Walk(v, e, pathToHere); err != nil {
   362→			return err
   363→		}
   364→	}
   365→
   366→	_, err = v.Visit(nil, nil)
   367→	return err
   368→}
   369→
   370→func ExtractSelectors(expr Expr) [][]*labels.Matcher {
   371→	var selectors [][]*labels.Matcher
   372→	Inspect(expr, func(node Node, _ []Node) error {
   373→		vs, ok := node.(*VectorSelector)
   374→		if ok {
   375→			selectors = append(selectors, vs.LabelMatchers)
   376→		}
   377→		return nil
   378→	})
   379→	return selectors
   380→}
   381→
   382→type inspector func(Node, []Node) error
   383→
   384→func (f inspector) Visit(node Node, path []Node) (Visitor, error) {
   385→	if err := f(node, path); err != nil {
   386→		return nil, err
   387→	}
   388→
   389→	return f, nil
   390→}
   391→
   392→// Inspect traverses an AST in depth-first order: It starts by calling
   393→// f(node, path); node must not be nil. If f returns a nil error, Inspect invokes f
   394→// for all the non-nil children of node, recursively.
   395→// Note: path may be overwritten after f returns; copy path if you need to retain it.
   396→func Inspect(node Node, f inspector) {
   397→	var pathBuf [4]Node        // To reduce allocations during recursion.
   398→	Walk(f, node, pathBuf[:0]) //nolint:errcheck
   399→}
   400→
   401→// ChildrenIter returns an iterator over all child nodes of a syntax tree node.
   402→func ChildrenIter(node Node) func(func(Node) bool) {
   403→	return func(yield func(Node) bool) {
   404→		// According to lore, these switches have significantly better performance than interfaces
   405→		switch n := node.(type) {
   406→		case *EvalStmt:
   407→			yield(n.Expr)
   408→		case Expressions:
   409→			for _, e := range n {
   410→				if !yield(e) {
   411→					return
   412→				}
   413→			}
   414→		case *AggregateExpr:
   415→			if n.Expr != nil {
   416→				if !yield(n.Expr) {
   417→					return
   418→				}
   419→			}
   420→			if n.Param != nil {
   421→				yield(n.Param)
   422→			}
   423→		case *BinaryExpr:
   424→			if !yield(n.LHS) {
   425→				return
   426→			}
   427→			yield(n.RHS)
   428→		case *Call:
   429→			for _, e := range n.Args {
   430→				if !yield(e) {
   431→					return
   432→				}
   433→			}
   434→		case *SubqueryExpr:
   435→			yield(n.Expr)
   436→		case *ParenExpr:
   437→			yield(n.Expr)
   438→		case *UnaryExpr:
   439→			yield(n.Expr)
   440→		case *MatrixSelector:
   441→			yield(n.VectorSelector)
   442→		case *StepInvariantExpr:
   443→			yield(n.Expr)
   444→		case *NumberLiteral, *StringLiteral, *VectorSelector:
   445→			// nothing to do
   446→		default:
   447→			panic(fmt.Errorf("promql.ChildrenIter: unhandled node type %T", node))
   448→		}
   449→	}
   450→}
   451→
   452→// Children returns a list of all child nodes of a syntax tree node.
   453→// Implemented for backwards-compatibility; prefer ChildrenIter().
   454→func Children(node Node) []Node {
   455→	ret := []Node{}
   456→	for e := range ChildrenIter(node) {
   457→		ret = append(ret, e)
   458→	}
   459→	return ret
   460→}
   461→
   462→// mergeRanges is a helper function to merge the PositionRanges of two Nodes.
   463→// Note that the arguments must be in the same order as they
   464→// occur in the input string.
   465→func mergeRanges(first, last Node) posrange.PositionRange {
   466→	return posrange.PositionRange{
   467→		Start: first.PositionRange().Start,
   468→		End:   last.PositionRange().End,
   469→	}
   470→}
   471→
   472→// PositionRange implements the Node interface.
   473→// This makes it possible to call mergeRanges on them.
   474→func (i *Item) PositionRange() posrange.PositionRange {
   475→	return posrange.PositionRange{
   476→		Start: i.Pos,
   477→		End:   i.Pos + posrange.Pos(len(i.Val)),
   478→	}
   479→}
   480→
   481→func (e *AggregateExpr) PositionRange() posrange.PositionRange {
   482→	return e.PosRange
   483→}
   484→
   485→func (e *BinaryExpr) PositionRange() posrange.PositionRange {
   486→	return mergeRanges(e.LHS, e.RHS)
   487→}
   488→
   489→func (e *DurationExpr) PositionRange() posrange.PositionRange {
   490→	if e.Op == STEP || e.Op == RANGE {
   491→		return posrange.PositionRange{
   492→			Start: e.StartPos,
   493→			End:   e.EndPos,
   494→		}
   495→	}
   496→	if e.RHS == nil {
   497→		return posrange.PositionRange{
   498→			Start: e.StartPos,
   499→			End:   e.RHS.PositionRange().End,
   500→		}
   501→	}
   502→	if e.LHS == nil {
   503→		return posrange.PositionRange{
   504→			Start: e.StartPos,
   505→			End:   e.RHS.PositionRange().End,
   506→		}
   507→	}
   508→	return mergeRanges(e.LHS, e.RHS)
   509→}
   510→
   511→func (e *Call) PositionRange() posrange.PositionRange {
   512→	return e.PosRange
   513→}
   514→
   515→func (e *EvalStmt) PositionRange() posrange.PositionRange {
   516→	return e.Expr.PositionRange()
   517→}
   518→
   519→func (e Expressions) PositionRange() posrange.PositionRange {
   520→	if len(e) == 0 {
   521→		// Position undefined.
   522→		return posrange.PositionRange{
   523→			Start: -1,
   524→			End:   -1,
   525→		}
   526→	}
   527→	return mergeRanges(e[0], e[len(e)-1])
   528→}
   529→
   530→func (e *MatrixSelector) PositionRange() posrange.PositionRange {
   531→	return posrange.PositionRange{
   532→		Start: e.VectorSelector.PositionRange().Start,
   533→		End:   e.EndPos,
   534→	}
   535→}
   536→
   537→func (e *SubqueryExpr) PositionRange() posrange.PositionRange {
   538→	return posrange.PositionRange{
   539→		Start: e.Expr.PositionRange().Start,
   540→		End:   e.EndPos,
   541→	}
   542→}
   543→
   544→func (e *NumberLiteral) PositionRange() posrange.PositionRange {
   545→	return e.PosRange
   546→}
   547→
   548→func (e *ParenExpr) PositionRange() posrange.PositionRange {
   549→	return e.PosRange
   550→}
   551→
   552→func (e *StringLiteral) PositionRange() posrange.PositionRange {
   553→	return e.PosRange
   554→}
   555→
   556→func (e *UnaryExpr) PositionRange() posrange.PositionRange {
   557→	return posrange.PositionRange{
   558→		Start: e.StartPos,
   559→		End:   e.Expr.PositionRange().End,
   560→	}
   561→}
   562→
   563→func (e *VectorSelector) PositionRange() posrange.PositionRange {
   564→	return e.PosRange
   565→}
