   462→// mergeRanges is a helper function to merge the PositionRanges of two Nodes.
   463→// Note that the arguments must be in the same order as they
   464→// occur in the input string.
   465→func mergeRanges(first, last Node) posrange.PositionRange {
   466→	return posrange.PositionRange{
   467→		Start: first.PositionRange().Start,
   468→		End:   last.PositionRange().End,
   469→	}
   470→}
   471→
   472→// PositionRange implements the Node interface.
   473→// This makes it possible to call mergeRanges on them.
   474→func (i *Item) PositionRange() posrange.PositionRange {
   475→	return posrange.PositionRange{
   476→		Start: i.Pos,
   477→		End:   i.Pos + posrange.Pos(len(i.Val)),
   478→	}
