   169→// newParser returns a new low-level parser instance from the pool.
   170→func newParser(input string, opts Options) *parser {
   171→	p := parserPool.Get().(*parser)
   172→
   173→	p.functions = Functions
   174→	p.injecting = false
   175→	p.parseErrors = nil
   176→	p.generatedParserResult = nil
   177→	p.lastClosing = posrange.Pos(0)
   178→	p.options = opts
   179→
   180→	// Clear lexer struct before reusing.
   181→	p.lex = Lexer{
   182→		input: input,
   183→		state: lexStatements,
   184→	}
   185→
   186→	return p
   187→}
