   189→// newParserWithFunctions returns a new low-level parser instance with custom functions.
   190→func newParserWithFunctions(input string, opts Options, functions map[string]*Function) *parser {
   191→	p := newParser(input, opts)
   192→	p.functions = functions
   193→	return p
   194→}
