   221→// ParseErr wraps a parsing error with line and position context.
   222→type ParseErr struct {
   223→	PositionRange posrange.PositionRange
   224→	Err           error
   225→	Query         string
   226→
   227→	// LineOffset is an additional line offset to be added. Only used inside unit tests.
   228→	LineOffset int
   229→}
   230→
   231→func (e *ParseErr) Error() string {
   232→	return fmt.Sprintf("%s: parse error: %s", e.PositionRange.StartPosInput(e.Query, e.LineOffset), e.Err)
   233→}
   234→
   235→type ParseErrors []ParseErr
   236→
   237→// Since producing multiple error messages might look weird when combined with error wrapping,
   238→// only the first error produced by the parser is included in the error string.
   239→// If getting the full error list is desired, it is recommended to typecast the error returned
   240→// by the parser to ParseErrors and work with the underlying slice.
   241→func (errs ParseErrors) Error() string {
   242→	if len(errs) != 0 {
   243→		return errs[0].Error()
   244→	}
   245→	// Should never happen
   246→	// Panicking while printing an error seems like a bad idea, so the
   247→	// situation is explained in the error message instead.
   248→	return "error contains no error message"
   249→}
   250→
   251→// EnrichParseError enriches a single or list of parse errors (used for unit tests and promtool).
   252→func EnrichParseError(err error, enrich func(parseErr *ParseErr)) {
   253→	var parseErr *ParseErr
   254→	if errors.As(err, &parseErr) {
   255→		enrich(parseErr)
   256→	}
   257→	var parseErrors ParseErrors
   258→	if errors.As(err, &parseErrors) {
   259→		for i, e := range parseErrors {
   260→			enrich(&e)
   261→			parseErrors[i] = e
   262→		}
   263→	}
   264→}
