   293→// addParseErrf formats the error and appends it to the list of parsing errors.
   294→func (p *parser) addParseErrf(positionRange posrange.PositionRange, format string, args ...any) {
   295→	p.addParseErr(positionRange, fmt.Errorf(format, args...))
   296→}
   297→
   298→// addParseErr appends the provided error to the list of parsing errors.
   299→func (p *parser) addParseErr(positionRange posrange.PositionRange, err error) {
   300→	perr := ParseErr{
   301→		PositionRange: positionRange,
   302→		Err:           err,
   303→		Query:         p.lex.input,
   304→	}
   305→
   306→	p.parseErrors = append(p.parseErrors, perr)
