   446→func (*parser) assembleVectorSelector(vs *VectorSelector) {
   447→	// If the metric name was set outside the braces, add a matcher for it.
   448→	// If the metric name was inside the braces we don't need to do anything.
   449→	if vs.Name != "" {
   450→		nameMatcher, err := labels.NewMatcher(labels.MatchEqual, labels.MetricName, vs.Name)
   451→		if err != nil {
   452→			panic(err) // Must not happen with labels.MatchEqual
   453→		}
   454→		vs.LabelMatchers = append(vs.LabelMatchers, nameMatcher)
   455→	}
   456→}
   457→
   458→func (p *parser) newAggregateExpr(op Item, modifier, args Node, overread bool) (ret *AggregateExpr) {
   459→	ret = modifier.(*AggregateExpr)
   460→	arguments := args.(Expressions)
   461→
   462→	ret.PosRange = posrange.PositionRange{
   463→		Start: op.Pos,
   464→		End:   p.lastClosing,
   465→	}
   466→	if overread {
   467→		ret.PosRange.End = p.lex.findPrevRightParen(p.lastClosing)
   468→	}
   469→
   470→	ret.Op = op.Typ
   471→
   472→	if len(arguments) == 0 {
   473→		p.addParseErrf(ret.PositionRange(), "no arguments for aggregate expression provided")
   474→
   475→		// Prevents invalid array accesses.
   476→		return ret
   477→	}
   478→
   479→	desiredArgs := 1
   480→	if ret.Op.IsAggregatorWithParam() {
   481→		if !p.options.EnableExperimentalFunctions && ret.Op.IsExperimentalAggregator() {
   482→			p.addParseErrf(ret.PositionRange(), "%s() is experimental and must be enabled with --enable-feature=promql-experimental-functions", ret.Op)
   483→			return ret
   484→		}
   485→		desiredArgs = 2
   486→
   487→		ret.Param = arguments[0]
   488→	}
   489→
   490→	if len(arguments) != desiredArgs {
   491→		p.addParseErrf(ret.PositionRange(), "wrong number of arguments for aggregate expression provided, expected %d, got %d", desiredArgs, len(arguments))
   492→		return ret
   493→	}
   494→
   495→	ret.Expr = arguments[desiredArgs-1]
   496→
   497→	return ret
   498→}
