   518→func (p *parser) histogramsIncreaseSeries(base, inc *histogram.FloatHistogram, times uint64) ([]SequenceValue, error) {
   519→	// Capture the hint set flag immediately after inc histogram is built.
   520→	// The base histogram's hint set flag was already captured.
   521→	hintSet := p.lastHistogramCounterResetHintSet
   522→	return p.histogramsSeries(base, inc, times, hintSet, func(a, b *histogram.FloatHistogram) (*histogram.FloatHistogram, error) {
   523→		res, _, _, err := a.Add(b)
   524→		return res, err
   525→	})
   526→}
   527→
   528→func (p *parser) histogramsDecreaseSeries(base, inc *histogram.FloatHistogram, times uint64) ([]SequenceValue, error) {
   529→	// Capture the hint set flag immediately after inc histogram is built.
   530→	hintSet := p.lastHistogramCounterResetHintSet
   531→	return p.histogramsSeries(base, inc, times, hintSet, func(a, b *histogram.FloatHistogram) (*histogram.FloatHistogram, error) {
   532→		res, _, _, err := a.Sub(b)
   533→		return res, err
   534→	})
   535→}
   536→
   537→func (*parser) histogramsSeries(base, inc *histogram.FloatHistogram, times uint64, counterResetHintSet bool,
   538→	combine func(*histogram.FloatHistogram, *histogram.FloatHistogram) (*histogram.FloatHistogram, error),
   539→) ([]SequenceValue, error) {
   540→	ret := make([]SequenceValue, times+1)
   541→	// Add an additional value (the base) for time 0, which we ignore in tests.
   542→	ret[0] = SequenceValue{Histogram: base, CounterResetHintSet: counterResetHintSet}
   543→	cur := base
   544→	for i := uint64(1); i <= times; i++ {
   545→		if cur.Schema > inc.Schema {
   546→			return nil, fmt.Errorf("error combining histograms: cannot merge from schema %d to %d", inc.Schema, cur.Schema)
   547→		}
   548→
   549→		var err error
   550→		cur, err = combine(cur.Copy(), inc)
   551→		if err != nil {
   552→			return ret, err
   553→		}
   554→		ret[i] = SequenceValue{Histogram: cur, CounterResetHintSet: counterResetHintSet}
   555→	}
   556→
   557→	return ret, nil
   558→}
   559→
   560→// buildHistogramFromMap is used in the grammar to take then individual parts of the histogram and complete it.
   561→func (p *parser) buildHistogramFromMap(desc *map[string]any) *histogram.FloatHistogram {
   562→	output := &histogram.FloatHistogram{}
   563→	// Reset the flag for each new histogram being built.
   564→	p.lastHistogramCounterResetHintSet = false
   565→
   566→	val, ok := (*desc)["schema"]
   567→	if ok {
   568→		schema, ok := val.(int64)
   569→		if ok {
   570→			output.Schema = int32(schema)
   571→		} else {
   572→			p.addParseErrf(p.yyParser.lval.item.PositionRange(), "error parsing schema number: %v", val)
   573→		}
   574→	}
   575→
   576→	val, ok = (*desc)["sum"]
   577→	if ok {
   578→		sum, ok := val.(float64)
   579→		if ok {
   580→			output.Sum = sum
   581→		} else {
   582→			p.addParseErrf(p.yyParser.lval.item.PositionRange(), "error parsing sum number: %v", val)
   583→		}
   584→	}
   585→	val, ok = (*desc)["count"]
   586→	if ok {
   587→		count, ok := val.(float64)
   588→		if ok {
   589→			output.Count = count
   590→		} else {
   591→			p.addParseErrf(p.yyParser.lval.item.PositionRange(), "error parsing count number: %v", val)
   592→		}
   593→	}
   594→
   595→	val, ok = (*desc)["z_bucket"]
   596→	if ok {
   597→		bucket, ok := val.(float64)
   598→		if ok {
   599→			output.ZeroCount = bucket
   600→		} else {
   601→			p.addParseErrf(p.yyParser.lval.item.PositionRange(), "error parsing z_bucket number: %v", val)
   602→		}
   603→	}
   604→	val, ok = (*desc)["z_bucket_w"]
   605→	if ok {
   606→		bucketWidth, ok := val.(float64)
   607→		if ok {
   608→			output.ZeroThreshold = bucketWidth
   609→		} else {
   610→			p.addParseErrf(p.yyParser.lval.item.PositionRange(), "error parsing z_bucket_w number: %v", val)
   611→		}
   612→	}
   613→	val, ok = (*desc)["custom_values"]
   614→	if ok {
   615→		customValues, ok := val.([]float64)
   616→		if ok {
   617→			output.CustomValues = customValues
   618→		} else {
   619→			p.addParseErrf(p.yyParser.lval.item.PositionRange(), "error parsing custom_values: %v", val)
   620→		}
   621→	}
   622→
   623→	val, ok = (*desc)["counter_reset_hint"]
   624→	if ok {
   625→		// Mark that the counter reset hint was explicitly specified.
   626→		p.lastHistogramCounterResetHintSet = true
   627→		resetHint, ok := val.(Item)
   628→
   629→		if ok {
   630→			switch resetHint.Typ {
   631→			case UNKNOWN_COUNTER_RESET:
   632→				output.CounterResetHint = histogram.UnknownCounterReset
   633→			case COUNTER_RESET:
   634→				output.CounterResetHint = histogram.CounterReset
   635→			case NOT_COUNTER_RESET:
   636→				output.CounterResetHint = histogram.NotCounterReset
   637→			case GAUGE_TYPE:
   638→				output.CounterResetHint = histogram.GaugeType
   639→			default:
   640→				p.addParseErrf(p.yyParser.lval.item.PositionRange(), "error parsing counter_reset_hint: unknown value %v", resetHint.Typ)
   641→			}
   642→		} else {
   643→			p.addParseErrf(p.yyParser.lval.item.PositionRange(), "error parsing counter_reset_hint: %v", val)
   644→		}
   645→	}
   646→
   647→	buckets, spans := p.buildHistogramBucketsAndSpans(desc, "buckets", "offset")
   648→	output.PositiveBuckets = buckets
   649→	output.PositiveSpans = spans
   650→
   651→	buckets, spans = p.buildHistogramBucketsAndSpans(desc, "n_buckets", "n_offset")
   652→	output.NegativeBuckets = buckets
   653→	output.NegativeSpans = spans
   654→
   655→	return output
   656→}
