   998→// addOffset is used to set the offset in the generated parser.
   999→func (p *parser) addOffset(e Node, offset time.Duration) {
  1000→	var orgoffsetp *time.Duration
  1001→	var orgoffsetexprp *DurationExpr
  1002→	var endPosp *posrange.Pos
  1003→
  1004→	switch s := e.(type) {
  1005→	case *VectorSelector:
  1006→		orgoffsetp = &s.OriginalOffset
  1007→		orgoffsetexprp = s.OriginalOffsetExpr
  1008→		endPosp = &s.PosRange.End
  1009→	case *MatrixSelector:
  1010→		vs, ok := s.VectorSelector.(*VectorSelector)
  1011→		if !ok {
  1012→			p.addParseErrf(e.PositionRange(), "ranges only allowed for vector selectors")
  1013→			return
  1014→		}
  1015→		orgoffsetp = &vs.OriginalOffset
  1016→		orgoffsetexprp = vs.OriginalOffsetExpr
  1017→		endPosp = &s.EndPos
  1018→	case *SubqueryExpr:
  1019→		orgoffsetp = &s.OriginalOffset
  1020→		orgoffsetexprp = s.OriginalOffsetExpr
  1021→		endPosp = &s.EndPos
  1022→	default:
  1023→		p.addParseErrf(e.PositionRange(), "offset modifier must be preceded by an instant vector selector or range vector selector or a subquery")
  1024→		return
  1025→	}
  1026→
  1027→	// it is already ensured by parseDuration func that there never will be a zero offset modifier
  1028→	switch {
  1029→	case *orgoffsetp != 0 || orgoffsetexprp != nil:
  1030→		p.addParseErrf(e.PositionRange(), "offset may not be set multiple times")
  1031→	case orgoffsetp != nil:
  1032→		*orgoffsetp = offset
  1033→	}
  1034→
  1035→	*endPosp = p.lastClosing
  1036→}
