  1077→func (p *parser) setAnchored(e Node) {
  1078→	if !p.options.EnableExtendedRangeSelectors {
  1079→		p.addParseErrf(e.PositionRange(), "anchored modifier is experimental and not enabled")
  1080→		return
  1081→	}
  1082→	switch s := e.(type) {
  1083→	case *VectorSelector:
  1084→		s.Anchored = true
  1085→		if s.Smoothed {
  1086→			p.addParseErrf(e.PositionRange(), "anchored and smoothed modifiers cannot be used together")
  1087→		}
  1088→	case *MatrixSelector:
  1089→		s.VectorSelector.(*VectorSelector).Anchored = true
  1090→		if s.VectorSelector.(*VectorSelector).Smoothed {
  1091→			p.addParseErrf(e.PositionRange(), "anchored and smoothed modifiers cannot be used together")
  1092→		}
  1093→	case *SubqueryExpr:
  1094→		p.addParseErrf(e.PositionRange(), "anchored modifier is not supported for subqueries")
  1095→	default:
  1096→		p.addParseErrf(e.PositionRange(), "anchored modifier not implemented")
  1097→	}
  1098→}
