  1123→// setTimestamp is used to set the timestamp from the @ modifier in the generated parser.
  1124→func (p *parser) setTimestamp(e Node, ts float64) {
  1125→	if math.IsInf(ts, -1) || math.IsInf(ts, 1) || math.IsNaN(ts) ||
  1126→		ts >= float64(math.MaxInt64) || ts <= float64(math.MinInt64) {
  1127→		p.addParseErrf(e.PositionRange(), "timestamp out of bounds for @ modifier: %f", ts)
  1128→	}
