   313→// unexpected creates a parser error complaining about an unexpected lexer item.
   314→// The item that is presented as unexpected is always the last item produced
   315→// by the lexer.
   316→func (p *parser) unexpected(context, expected string) {
   317→	var errMsg strings.Builder
   318→
   319→	// Do not report lexer errors twice
   320→	if p.yyParser.lval.item.Typ == ERROR {
