   358→// Lex is expected by the yyLexer interface of the yacc generated parser.
   359→// It writes the next Item provided by the lexer to the provided pointer address.
   360→// Comments are skipped.
   361→//
   362→// The yyLexer interface is currently implemented by the parser to allow
   363→// the generated and non-generated parts to work together with regards to lookahead
   364→// and error handling.
   365→//
   366→// For more information, see https://pkg.go.dev/golang.org/x/tools/cmd/goyacc.
   367→func (p *parser) Lex(lval *yySymType) int {
   368→	var typ ItemType
   369→
   370→	if p.injecting {
   371→		p.injecting = false
   372→		return int(p.inject)
   373→	}
   374→	// Skip comments.
   375→	for {
   376→		p.lex.NextItem(&lval.item)
   377→		typ = lval.item.Typ
   378→		if typ != COMMENT {
   379→			break
   380→		}
   381→	}
   382→
   383→	switch typ {
   384→	case ERROR:
   385→		pos := posrange.PositionRange{
   386→			Start: p.lex.start,
   387→			End:   posrange.Pos(len(p.lex.input)),
   388→		}
   389→		p.addParseErr(pos, errors.New(p.yyParser.lval.item.Val))
   390→
   391→		// Tells yacc that this is the end of input.
   392→		return 0
   393→	case EOF:
   394→		lval.item.Typ = EOF
   395→		p.InjectItem(0)
   396→	case RIGHT_BRACE, RIGHT_PAREN, RIGHT_BRACKET, DURATION, NUMBER:
   397→		p.lastClosing = lval.item.Pos + posrange.Pos(len(lval.item.Val))
   398→	}
   399→
   400→	return int(typ)
   401→}
