   710→// expectType checks the type of the node and raises an error if it
   711→// is not of the expected type.
   712→func (p *parser) expectType(node Node, want ValueType, context string) {
   713→	t := p.checkAST(node)
   714→	if t != want {
   715→		p.addParseErrf(node.PositionRange(), "expected type %s in %s, got %s", DocumentedType(want), context, DocumentedType(t))
   716→	}
   717→}
   718→
   719→// checkAST checks the validity of the provided AST. This includes type checking.
   720→func (p *parser) checkAST(node Node) (typ ValueType) {
   721→	// For expressions the type is determined by their Type function.
   722→	// Lists do not have a type but are not invalid either.
   723→	switch n := node.(type) {
   724→	case Expressions:
   725→		typ = ValueTypeNone
   726→	case Expr:
   727→		typ = n.Type()
   728→	default:
   729→		p.addParseErrf(node.PositionRange(), "unknown node type: %T", node)
   730→	}
   731→
   732→	// Recursively check correct typing for child nodes and raise
   733→	// errors in case of bad typing.
   734→	switch n := node.(type) {
   735→	case *EvalStmt:
   736→		ty := p.checkAST(n.Expr)
   737→		if ty == ValueTypeNone {
   738→			p.addParseErrf(n.Expr.PositionRange(), "evaluation statement must have a valid expression type but got %s", DocumentedType(ty))
   739→		}
   740→
   741→	case Expressions:
   742→		for _, e := range n {
   743→			ty := p.checkAST(e)
   744→			if ty == ValueTypeNone {
   745→				p.addParseErrf(e.PositionRange(), "expression must have a valid expression type but got %s", DocumentedType(ty))
   746→			}
   747→		}
   748→	case *AggregateExpr:
   749→		if !n.Op.IsAggregator() {
   750→			p.addParseErrf(n.PositionRange(), "aggregation operator expected in aggregation expression but got %q", n.Op)
   751→		}
   752→		p.expectType(n.Expr, ValueTypeVector, "aggregation expression")
   753→		if n.Op == TOPK || n.Op == BOTTOMK || n.Op == QUANTILE || n.Op == LIMITK || n.Op == LIMIT_RATIO {
   754→			p.expectType(n.Param, ValueTypeScalar, "aggregation parameter")
   755→		}
   756→		if n.Op == COUNT_VALUES {
   757→			p.expectType(n.Param, ValueTypeString, "aggregation parameter")
   758→		}
   759→
   760→	case *BinaryExpr:
   761→		lt := p.checkAST(n.LHS)
   762→		rt := p.checkAST(n.RHS)
   763→
   764→		// opRange returns the PositionRange of the operator part of the BinaryExpr.
   765→		// This is made a function instead of a variable, so it is lazily evaluated on demand.
   766→		opRange := func() (r posrange.PositionRange) {
   767→			// Remove whitespace at the beginning and end of the range.
   768→			for r.Start = n.LHS.PositionRange().End; isSpace(rune(p.lex.input[r.Start])); r.Start++ {
   769→			}
   770→			for r.End = n.RHS.PositionRange().Start - 1; isSpace(rune(p.lex.input[r.End])); r.End-- {
   771→			}
   772→			return r
   773→		}
   774→
   775→		if n.ReturnBool && !n.Op.IsComparisonOperator() {
   776→			p.addParseErrf(opRange(), "bool modifier can only be used on comparison operators")
   777→		}
   778→
   779→		if n.Op.IsComparisonOperator() && !n.ReturnBool && n.RHS.Type() == ValueTypeScalar && n.LHS.Type() == ValueTypeScalar {
   780→			p.addParseErrf(opRange(), "comparisons between scalars must use BOOL modifier")
   781→		}
   782→
   783→		if n.Op.IsSetOperator() && n.VectorMatching.Card == CardOneToOne {
   784→			n.VectorMatching.Card = CardManyToMany
   785→		}
   786→
   787→		for _, l1 := range n.VectorMatching.MatchingLabels {
   788→			for _, l2 := range n.VectorMatching.Include {
   789→				if l1 == l2 && n.VectorMatching.On {
   790→					p.addParseErrf(opRange(), "label %q must not occur in ON and GROUP clause at once", l1)
   791→				}
   792→			}
   793→		}
   794→
   795→		if !n.Op.IsOperator() {
   796→			p.addParseErrf(n.PositionRange(), "binary expression does not support operator %q", n.Op)
   797→		}
   798→		if lt != ValueTypeScalar && lt != ValueTypeVector {
   799→			p.addParseErrf(n.LHS.PositionRange(), "binary expression must contain only scalar and instant vector types")
   800→		}
   801→		if rt != ValueTypeScalar && rt != ValueTypeVector {
   802→			p.addParseErrf(n.RHS.PositionRange(), "binary expression must contain only scalar and instant vector types")
   803→		}
   804→
   805→		switch {
   806→		case (lt != ValueTypeVector || rt != ValueTypeVector) && n.VectorMatching != nil:
   807→			if len(n.VectorMatching.MatchingLabels) > 0 {
   808→				p.addParseErrf(n.PositionRange(), "vector matching only allowed between instant vectors")
   809→			}
   810→			if n.VectorMatching.FillValues.LHS != nil || n.VectorMatching.FillValues.RHS != nil {
   811→				p.addParseErrf(n.PositionRange(), "filling in missing series only allowed between instant vectors")
   812→			}
   813→			n.VectorMatching = nil
   814→		case n.Op.IsSetOperator(): // Both operands are Vectors.
   815→			if n.VectorMatching.Card == CardOneToMany || n.VectorMatching.Card == CardManyToOne {
   816→				p.addParseErrf(n.PositionRange(), "no grouping allowed for %q operation", n.Op)
   817→			}
   818→			if n.VectorMatching.Card != CardManyToMany {
   819→				p.addParseErrf(n.PositionRange(), "set operations must always be many-to-many")
   820→			}
   821→			if n.VectorMatching.FillValues.LHS != nil || n.VectorMatching.FillValues.RHS != nil {
   822→				p.addParseErrf(n.PositionRange(), "filling in missing series not allowed for set operators")
   823→			}
   824→		}
   825→
   826→		if (lt == ValueTypeScalar || rt == ValueTypeScalar) && n.Op.IsSetOperator() {
   827→			p.addParseErrf(n.PositionRange(), "set operator %q not allowed in binary scalar expression", n.Op)
   828→		}
   829→
   830→	case *Call:
   831→		nargs := len(n.Func.ArgTypes)
   832→		if n.Func.Variadic == 0 {
   833→			if nargs != len(n.Args) {
   834→				p.addParseErrf(n.PositionRange(), "expected %d argument(s) in call to %q, got %d", nargs, n.Func.Name, len(n.Args))
   835→			}
   836→		} else {
   837→			na := nargs - 1
   838→			if na > len(n.Args) {
   839→				p.addParseErrf(n.PositionRange(), "expected at least %d argument(s) in call to %q, got %d", na, n.Func.Name, len(n.Args))
   840→			} else if nargsmax := na + n.Func.Variadic; n.Func.Variadic > 0 && nargsmax < len(n.Args) {
   841→				p.addParseErrf(n.PositionRange(), "expected at most %d argument(s) in call to %q, got %d", nargsmax, n.Func.Name, len(n.Args))
   842→			}
   843→		}
   844→
   845→		if n.Func.Name == "info" && len(n.Args) > 1 {
   846→			// Check the type is correct first
   847→			if n.Args[1].Type() != ValueTypeVector {
   848→				p.addParseErrf(node.PositionRange(), "expected type %s in %s, got %s", DocumentedType(ValueTypeVector), fmt.Sprintf("call to function %q", n.Func.Name), DocumentedType(n.Args[1].Type()))
   849→			}
   850→			// Check the vector selector in the input doesn't contain a metric name
   851→			if vs, ok := n.Args[1].(*VectorSelector); ok && vs.Name != "" {
   852→				p.addParseErrf(n.Args[1].PositionRange(), "expected label selectors only, got vector selector instead")
   853→			} else if ok {
   854→				// Set Vector Selector flag to bypass empty matcher check
   855→				vs.BypassEmptyMatcherCheck = true
   856→			} else {
   857→				p.addParseErrf(n.Args[1].PositionRange(), "expected label selectors only")
   858→			}
   859→		}
   860→
   861→		for i, arg := range n.Args {
   862→			if i >= len(n.Func.ArgTypes) {
   863→				if n.Func.Variadic == 0 {
   864→					// This is not a vararg function so we should not check the
   865→					// type of the extra arguments.
   866→					break
   867→				}
   868→				i = len(n.Func.ArgTypes) - 1
   869→			}
   870→			if t := p.checkAST(arg); t != n.Func.ArgTypes[i] {
   871→				p.addParseErrf(arg.PositionRange(), "expected type %s in call to function %q, got %s", DocumentedType(n.Func.ArgTypes[i]), n.Func.Name, DocumentedType(t))
   872→			}
   873→		}
   874→
   875→	case *ParenExpr:
   876→		p.checkAST(n.Expr)
   877→
   878→	case *UnaryExpr:
   879→		if n.Op != ADD && n.Op != SUB {
   880→			p.addParseErrf(n.PositionRange(), "only + and - operators allowed for unary expressions")
   881→		}
   882→		if t := p.checkAST(n.Expr); t != ValueTypeScalar && t != ValueTypeVector {
   883→			p.addParseErrf(n.PositionRange(), "unary expression only allowed on expressions of type scalar or instant vector, got %q", DocumentedType(t))
   884→		}
   885→
   886→	case *SubqueryExpr:
   887→		ty := p.checkAST(n.Expr)
   888→		if ty != ValueTypeVector {
   889→			p.addParseErrf(n.PositionRange(), "subquery is only allowed on instant vector, got %s instead", ty)
   890→		}
   891→	case *MatrixSelector:
   892→		p.checkAST(n.VectorSelector)
   893→
   894→	case *VectorSelector:
   895→		if n.Name != "" {
   896→			// In this case the last LabelMatcher is checking for the metric name
   897→			// set outside the braces. This checks if the name has already been set
   898→			// previously.
   899→			for _, m := range n.LabelMatchers[0 : len(n.LabelMatchers)-1] {
   900→				if m != nil && m.Name == labels.MetricName {
   901→					p.addParseErrf(n.PositionRange(), "metric name must not be set twice: %q or %q", n.Name, m.Value)
   902→				}
   903→			}
   904→
   905→			// Skip the check for non-empty matchers because an explicit
   906→			// metric name is a non-empty matcher.
   907→			break
   908→		}
   909→		if !n.BypassEmptyMatcherCheck {
   910→			// A Vector selector must contain at least one non-empty matcher to prevent
   911→			// implicit selection of all metrics (e.g. by a typo).
   912→			notEmpty := false
   913→			for _, lm := range n.LabelMatchers {
   914→				if lm != nil && !lm.Matches("") {
   915→					notEmpty = true
   916→					break
   917→				}
   918→			}
   919→			if !notEmpty {
   920→				p.addParseErrf(n.PositionRange(), "vector selector must contain at least one non-empty matcher")
   921→			}
   922→		}
   923→
   924→	case *NumberLiteral, *StringLiteral:
   925→		// Nothing to do for terminals.
   926→
   927→	default:
   928→		p.addParseErrf(n.PositionRange(), "unknown node type: %T", node)
   929→	}
   930→	return typ
   931→}
