  1041→	var orgoffsetexprp **DurationExpr
  1042→	var endPosp *posrange.Pos
  1043→
  1044→	switch s := e.(type) {
  1045→	case *VectorSelector:
  1046→		orgoffsetp = &s.OriginalOffset
  1047→		orgoffsetexprp = &s.OriginalOffsetExpr
  1048→		endPosp = &s.PosRange.End
  1049→	case *MatrixSelector:
