  1051→		if !ok {
  1052→			p.addParseErrf(e.PositionRange(), "ranges only allowed for vector selectors")
  1053→			return
  1054→		}
  1055→		orgoffsetp = &vs.OriginalOffset
  1056→		orgoffsetexprp = &vs.OriginalOffsetExpr
  1057→		endPosp = &s.EndPos
  1058→	case *SubqueryExpr:
