  1077→func (p *parser) setAnchored(e Node) {
  1078→	if !p.options.EnableExtendedRangeSelectors {
  1079→		p.addParseErrf(e.PositionRange(), "anchored modifier is experimental and not enabled")
  1080→		return
  1081→	}
  1082→	switch s := e.(type) {
  1083→	case *VectorSelector:
  1084→		s.Anchored = true
  1085→		if s.Smoothed {
  1086→			p.addParseErrf(e.PositionRange(), "anchored and smoothed modifiers cannot be used together")
  1087→		}
  1088→	case *MatrixSelector:
  1089→		s.VectorSelector.(*VectorSelector).Anchored = true
  1090→		if s.VectorSelector.(*VectorSelector).Smoothed {
  1091→			p.addParseErrf(e.PositionRange(), "anchored and smoothed modifiers cannot be used together")
  1092→		}
  1093→	case *SubqueryExpr:
  1094→		p.addParseErrf(e.PositionRange(), "anchored modifier is not supported for subqueries")
  1095→	default:
  1096→		p.addParseErrf(e.PositionRange(), "anchored modifier not implemented")
  1097→	}
  1098→}
  1099→
  1100→func (p *parser) setSmoothed(e Node) {
  1101→	if !p.options.EnableExtendedRangeSelectors {
  1102→		p.addParseErrf(e.PositionRange(), "smoothed modifier is experimental and not enabled")
  1103→		return
  1104→	}
  1105→	switch s := e.(type) {
  1106→	case *VectorSelector:
  1107→		s.Smoothed = true
  1108→		if s.Anchored {
  1109→			p.addParseErrf(e.PositionRange(), "anchored and smoothed modifiers cannot be used together")
  1110→		}
  1111→	case *MatrixSelector:
  1112→		s.VectorSelector.(*VectorSelector).Smoothed = true
  1113→		if s.VectorSelector.(*VectorSelector).Anchored {
  1114→			p.addParseErrf(e.PositionRange(), "anchored and smoothed modifiers cannot be used together")
  1115→		}
  1116→	case *SubqueryExpr:
  1117→		p.addParseErrf(e.PositionRange(), "smoothed modifier is not supported for subqueries")
  1118→	default:
  1119→		p.addParseErrf(e.PositionRange(), "smoothed modifier not implemented")
  1120→	}
  1121→}
  1122→
  1123→// setTimestamp is used to set the timestamp from the @ modifier in the generated parser.
  1124→func (p *parser) setTimestamp(e Node, ts float64) {
  1125→	if math.IsInf(ts, -1) || math.IsInf(ts, 1) || math.IsNaN(ts) ||
  1126→		ts >= float64(math.MaxInt64) || ts <= float64(math.MinInt64) {
  1127→		p.addParseErrf(e.PositionRange(), "timestamp out of bounds for @ modifier: %f", ts)
  1128→	}
  1129→	var timestampp **int64
  1130→	var endPosp *posrange.Pos
  1131→
  1132→	timestampp, _, endPosp, ok := p.getAtModifierVars(e)
  1133→	if !ok {
  1134→		return
  1135→	}
  1136→
  1137→	if timestampp != nil {
  1138→		*timestampp = new(int64)
  1139→		**timestampp = timestamp.FromFloatSeconds(ts)
  1140→	}
  1141→
  1142→	*endPosp = p.lastClosing
  1143→}
  1144→
  1145→// setAtModifierPreprocessor is used to set the preprocessor for the @ modifier.
  1146→func (p *parser) setAtModifierPreprocessor(e Node, op Item) {
  1147→	_, preprocp, endPosp, ok := p.getAtModifierVars(e)
  1148→	if !ok {
  1149→		return
  1150→	}
  1151→
  1152→	if preprocp != nil {
  1153→		*preprocp = op.Typ
  1154→	}
  1155→
  1156→	*endPosp = p.lastClosing
  1157→}
  1158→
  1159→func (p *parser) getAtModifierVars(e Node) (**int64, *ItemType, *posrange.Pos, bool) {
  1160→	var (
  1161→		timestampp **int64
  1162→		preprocp   *ItemType
  1163→		endPosp    *posrange.Pos
  1164→	)
  1165→	switch s := e.(type) {
  1166→	case *VectorSelector:
  1167→		timestampp = &s.Timestamp
  1168→		preprocp = &s.StartOrEnd
  1169→		endPosp = &s.PosRange.End
  1170→	case *MatrixSelector:
  1171→		vs, ok := s.VectorSelector.(*VectorSelector)
  1172→		if !ok {
  1173→			p.addParseErrf(e.PositionRange(), "ranges only allowed for vector selectors")
  1174→			return nil, nil, nil, false
  1175→		}
  1176→		preprocp = &vs.StartOrEnd
  1177→		timestampp = &vs.Timestamp
  1178→		endPosp = &s.EndPos
  1179→	case *SubqueryExpr:
  1180→		preprocp = &s.StartOrEnd
  1181→		timestampp = &s.Timestamp
  1182→		endPosp = &s.EndPos
  1183→	default:
  1184→		p.addParseErrf(e.PositionRange(), "@ modifier must be preceded by an instant vector selector or range vector selector or a subquery")
  1185→		return nil, nil, nil, false
  1186→	}
  1187→
  1188→	if *timestampp != nil || (*preprocp) == START || (*preprocp) == END {
  1189→		p.addParseErrf(e.PositionRange(), "@ <timestamp> may not be set multiple times")
  1190→		return nil, nil, nil, false
  1191→	}
  1192→
  1193→	return timestampp, preprocp, endPosp, true
  1194→}
  1195→
  1196→func (p *parser) experimentalDurationExpr(e Expr) {
  1197→	if !p.options.ExperimentalDurationExpr {
  1198→		p.addParseErrf(e.PositionRange(), "experimental duration expression is not enabled")
  1199→	}
  1200→}
  1201→
  1202→func MustLabelMatcher(mt labels.MatchType, name, val string) *labels.Matcher {
  1203→	m, err := labels.NewMatcher(mt, name, val)
  1204→	if err != nil {
  1205→		panic(err)
  1206→	}
  1207→	return m
  1208→}
